    let finalParams = parameters;
    if (!finalParams || (Array.isArray(finalParams) && finalParams.length === 0)) {
      // 如果前端没传参数配置，自动解析
      const parsedParams = parseWorkflowParams(parsedContent);
      finalParams = parsedParams;
