      const containerName = node.containerName || `comfyui-${node.name.replace(/\s+/g, '-').toLowerCase()}`;
      const containerStatus = containerStatuses[containerName] || 'unknown';
      return {
        ...node,
        containerStatus,
        containerName,
      };
    });

    res.json({ success: true, data: enrichedNodes });
  } catch (error) {
