/** 从系统配置获取守护进程 Base URL */
async function getDaemonBaseUrl(): Promise<string> {
  const config = await prisma.config.findFirst({
    where: { key: 'model_downloader_url' },
  });
  if (!config?.value) {
    throw new Error('服务器 API 地址未配置，请在系统设置中配置 model_downloader_url');
